<template><section class="page"><div class="panel"><el-table :data="rows" v-loading="loading"><el-table-column prop="tracking_no" label="运单号"/><el-table-column prop="external_event_id" label="外部事件"/><el-table-column prop="raw_status" label="原始状态"/><el-table-column prop="signature_valid" label="验签"><template #default="s"><el-tag :type="s.row.signature_valid?'success':'danger'">{{s.row.signature_valid?'通过':'失败'}}</el-tag></template></el-table-column><el-table-column prop="process_status" label="处理状态"/><el-table-column prop="received_time" label="接收时间"><template #default="s">{{formatTime(s.row.received_time)}}</template></el-table-column></el-table></div></section></template><script setup lang="ts">import { onMounted, ref } from 'vue'; import { http } from '../api/http'; import { formatTime } from '../utils/status'; const rows=ref<any[]>([]); const loading=ref(false); async function load(){loading.value=true; try{rows.value=await http.get('/raw-events')} finally{loading.value=false}} onMounted(load)</script>
